class User {
  String name;
  int age;
  User(this.name, this.age);
}

class MyController extends GetxController {
  Rx<User> user = User('Alice', 30).obs;

  void updateUser() {
    // Update the whole object
    user.value = User('Bob', 25);
    // Or modify properties and refresh
    user.update((user) {
      user?.name = 'Charlie';
    });
  }
}

